// Extrair o HTML do response da Anthropic API
const response = $input.first().json;
let html = '';

if (response.content) {
  for (const block of response.content) {
    if (block.type === 'text') {
      html += block.text;
    }
  }
}

// Extrair so o HTML se vier com markdown code block
const htmlMatch = html.match(/```html\n([\s\S]*?)\n```/);
if (htmlMatch) {
  html = htmlMatch[1];
} else if (html.includes('<!DOCTYPE') || html.includes('<html')) {
  // ja e HTML puro
} else {
  // wrap em HTML basico
  html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Relatorio Semanal</title></head><body>${html}</body></html>`;
}

return [{ json: { html, date: new Date().toISOString().slice(0,10) } }];
